"use client";
import React, { useState } from "react";
import { Package, Plus, AlertTriangle, CheckCircle, RefreshCw } from "lucide-react";

interface InventoryItem {
  id: string;
    name: string;
      quantity: number; // الكمية المتاحة حالياً (كغم أو صندوق)
        minLimit: number; // حد الأمان (التنبيه قبل النفاذ)
          unit: string; // الوحدة: كغم أو كرتونة
            lastUpdated: string;
            }

            export default function InventoryPage() {
              const [itemName, setItemName] = useState("");
                const [quantity, setQuantity] = useState("");
                  const [minLimit, setMinLimit] = useState("");
                    const [unit, setUnit] = useState("كغم");

                      // بيانات تجريبية لجرد أصناف الخضار والفواكه بالمحل حالياً
                        const [stock, setStock] = useState<InventoryItem[]>([
                            { id: "1", name: "بندورة نخب أول", quantity: 1200, minLimit: 300, unit: "كغم", lastUpdated: "2026-06-10" },
                                { id: "2", name: "خيار بلدي مفرز", quantity: 150, minLimit: 200, unit: "كغم", lastUpdated: "2026-06-10" }, // هاد هيطلع تنبيه أحمر
                                    { id: "3", name: "بطاطا حلوة (صناديق)", quantity: 45, minLimit: 10, unit: "صندوق", lastUpdated: "2026-06-09" },
                                        { id: "4", name: "بصل أحمر فرنسي", quantity: 280, minLimit: 300, unit: "كغم", lastUpdated: "2026-06-10" }, // تنبيه أحمر
                                          ]);

                                            // إضافة صنف جديد للمخزن أو تعديل جرد
                                              const handleAddToInventory = (e: React.FormEvent) => {
                                                  e.preventDefault();
                                                      if (!itemName || !quantity || !minLimit) return;

                                                          const newItem: InventoryItem = {
                                                                id: Date.now().toString(),
                                                                      name: itemName,
                                                                            quantity: parseFloat(quantity),
                                                                                  minLimit: parseFloat(minLimit),
                                                                                        unit,
                                                                                              lastUpdated: new Date().toISOString().split('T')[0],
                                                                                                  };

                                                                                                      setStock([newItem, ...stock]);
                                                                                                          alert(`تم إدراج وتحديث بضاعة: ${itemName} في المخزن بنجاح.`);
                                                                                                              
                                                                                                                  // تصفير الخانات
                                                                                                                      setItemName("");
                                                                                                                          setQuantity("");
                                                                                                                              setMinLimit("");
                                                                                                                                };

                                                                                                                                  return (
                                                                                                                                      <div className="space-y-6">
                                                                                                                                            {/* الهيدر العلوي */}
                                                                                                                                                  <div className="bg-slate-800 p-5 rounded-xl border border-slate-700 shadow-md">
                                                                                                                                                          <h1 className="text-xl font-bold text-emerald-400 flex items-center gap-2">
                                                                                                                                                                    <Package className="w-6 h-6" /> مستودع وجرد بضاعة المحل الحالية
                                                                                                                                                                            </h1>
                                                                                                                                                                                    <p className="text-slate-400 text-xs mt-1">مراقبة أوزان الخضار المتاحة وتنبيهات النواقص التلقائية قبل نفاد الصنف.</p>
                                                                                                                                                                                          </div>

                                                                                                                                                                                                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                                                                                                                                                                                                        
                                                                                                                                                                                                                {/* نموذج جرد وإدخال صنف جديد أو شحنة جديدة واصلة للمحل */}
                                                                                                                                                                                                                        <div className="lg:col-span-1">
                                                                                                                                                                                                                                  <form onSubmit={handleAddToInventory} className="bg-slate-800 p-5 rounded-xl border border-slate-700 space-y-4">
                                                                                                                                                                                                                                              <h3 className="text-sm font-bold text-slate-200 border-b border-slate-700 pb-2">📦 جرد صنف / شحنة جديدة</h3>
                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                      <div>
                                                                                                                                                                                                                                                                                    <label className="block text-xs text-slate-400 mb-1">اسم المادة (بندورة، موز، تفاح)</label>
                                                                                                                                                                                                                                                                                                  <input 
                                                                                                                                                                                                                                                                                                                  type="text" required placeholder="اسم الصنف"
                                                                                                                                                                                                                                                                                                                                  value={itemName} onChange={(e) => setItemName(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                  className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:outline-none focus:border-emerald-500 text-sm"
                                                                                                                                                                                                                                                                                                                                                                />
                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                        <div className="grid grid-cols-2 gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                      <div>
                                                                                                                                                                                                                                                                                                                                                                                                                      <label className="block text-xs text-slate-400 mb-1">الكمية المتوفرة</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                      <input 
                                                                                                                                                                                                                                                                                                                                                                                                                                                        type="number" step="0.01" required placeholder="0.00"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          value={quantity} onChange={(e) => setQuantity(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:outline-none focus:border-emerald-500 text-sm"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <label className="block text-xs text-slate-400 mb-1">وحدة القياس</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <select 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          value={unit} onChange={(e) => setUnit(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:outline-none focus:border-emerald-500 text-sm"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <option value="كغم">كغم (كيلو)</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <option value="صندوق">صندوق / سحارة</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <option value="طن">طن</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </select>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <label className="block text-xs text-slate-400 mb-1">حد الأمان (التنبيه عند النقص)</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <input 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    type="number" step="0.01" required placeholder="إذا نزلت البضاعة عن هاد الوزن هينبهك"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    value={minLimit} onChange={(e) => setMinLimit(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-100 focus:outline-none focus:border-emerald-500 text-sm"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        type="submit"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 rounded-lg font-medium text-sm text-emerald-400 flex items-center justify-center gap-1 transition-colors border border-emerald-500/20 shadow-md"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <Plus className="w-4 h-4" /> تحديث كميات المخزن
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </form>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* جدول عرض الجرد مع مؤشرات التنبيه الملونة */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="lg:col-span-2 bg-slate-800 p-5 rounded-xl border border-slate-700 flex flex-col justify-between min-h-[380px]">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="overflow-x-auto w-full">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <h3 className="text-sm font-bold text-slate-200 mb-3 flex items-center gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  📋 حالة جرد الأصناف الحالية في المحل
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </h3>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <table className="w-full text-right border-collapse">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <thead>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <tr className="border-b border-slate-700 text-slate-400 text-xs">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <th className="pb-3 font-semibold">الصنف</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <th className="pb-3 font-semibold text-center">الكمية المتوفرة</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <th className="pb-3 font-semibold text-center">حد الأمان</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <th className="pb-3 font-semibold text-center">الحالة الإشعارية</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <th className="pb-3 text-left">آخر تحديث</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </tr>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </thead>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <tbody className="divide-y divide-slate-700/50 text-sm">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {stock.map((item) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const isLow = item.quantity <= item.minLimit;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <tr key={item.id} className="hover:bg-slate-700/30 transition-colors">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <td className="py-3.5 font-bold text-slate-200">{item.name}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <td className="py-3.5 text-center text-slate-100 font-semibold">{item.quantity} {item.unit}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <td className="py-3.5 text-center text-slate-400 font-mono">{item.minLimit} {item.unit}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <td className="py-3.5 text-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {isLow ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold bg-rose-500/10 text-rose-400 border border-rose-500/20 animate-pulse">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <AlertTriangle className="w-3.5 h-3.5" /> أوشك على النفاذ!
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold bg-emerald-500/10 text-emerald-400 border border-emerald-500/20">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <CheckCircle className="w-3.5 h-3.5" /> متوفر بكثرة
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <td className="py-3.5 text-left text-slate-400 font-mono text-xs">{item.lastUpdated}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </tr>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        })}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </tbody>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </table>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                